// Fetch ALL pages from Airtable Contacts table and group by customer email
const AIRTABLE_TOKEN = process.env.AIRTABLE_TOKEN;
const CONTACTS_URL = 'https://api.airtable.com/v0/appT9NVuu8MyFHFsj/tblHtfXkcsmWjk1aQ';
const CUSTOMERS_URL = 'https://api.airtable.com/v0/appT9NVuu8MyFHFsj/tblxs0QLftdL72IUV';
const BATCH_SIZE = 10;

// Step 1: Fetch all contact records
const allRecords = [];
let offset = null;
do {
  const url = CONTACTS_URL + '?pageSize=100' + (offset ? '&offset=' + offset : '');
  const page = await this.helpers.httpRequest({
    method: 'GET',
    url,
    headers: { 'Authorization': 'Bearer ' + AIRTABLE_TOKEN }
  });
  allRecords.push(...(page.records || []));
  offset = page.offset;
  if (offset) await new Promise(r => setTimeout(r, 200));
} while (offset);

// Step 2: Group by email
const customerMap = {};
for (const rec of allRecords) {
  const f = rec.fields;
  const email = (f.Email || '').toLowerCase().trim();
  if (!email || email.includes('metabelly')) continue;

  if (!customerMap[email]) {
    customerMap[email] = {
      name: f.Customer || '(unknown)',
      email,
      phone: f.Phone || '',
      totalOrders: 0,
      totalSpent: 0,
      products: [],
      lastOrderDate: null,
      gmailLinks: []
    };
  }

  const c = customerMap[email];
  if (f.Customer && f.Customer !== '(unknown)') c.name = f.Customer;
  if (f.Phone) c.phone = f.Phone;
  if (f.Total && Number(f.Total) > 0) {
    c.totalOrders++;
    c.totalSpent += Number(f.Total);
  }
  if (f.Product) c.products.push(f.Product);
  if (f['Gmail Link']) c.gmailLinks.push(f['Gmail Link']);
  if (f.Received) {
    const d = new Date(f.Received);
    if (!c.lastOrderDate || d > new Date(c.lastOrderDate)) {
      c.lastOrderDate = f.Received;
    }
  }
}

// Step 3: Batch insert into Customers table
const customers = Object.values(customerMap);
let inserted = 0;

for (let i = 0; i < customers.length; i += BATCH_SIZE) {
  const batch = customers.slice(i, i + BATCH_SIZE);
  const records = batch.map(c => ({
    fields: {
      Name: c.name,
      Email: c.email,
      Phone: c.phone || '',
      'Total Orders': c.totalOrders,
      'Total Spent': Math.round(c.totalSpent * 100) / 100,
      'Products Bought': [...new Set(c.products)].join('\n'),
      'Last Order Date': c.lastOrderDate || null,
      Notes: c.gmailLinks.slice(0, 5).join('\n')
    }
  })).map(r => {
    // Remove empty/null fields
    Object.keys(r.fields).forEach(k => {
      if (r.fields[k] === '' || r.fields[k] === null || r.fields[k] === 0) delete r.fields[k];
    });
    return r;
  });

  await this.helpers.httpRequest({
    method: 'POST',
    url: CUSTOMERS_URL,
    headers: {
      'Authorization': 'Bearer ' + AIRTABLE_TOKEN,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({ records })
  });

  inserted += batch.length;
  await new Promise(r => setTimeout(r, 250));
}

return [{ json: { success: true, uniqueCustomers: customers.length, inserted } }];
